/// Convert markdown text to HTML.
pub fn to_html(markdown: &str) -> String {
    let mut html = String::new();
    for line in markdown.lines() {
        html.push_str(&parse_line(line));
        html.push('\n');
    }
    html
}

fn parse_line(line: &str) -> String {
    let trimmed = line.trim_start();
    // Check for headings
    let hash_count = trimmed.chars().take_while(|c| *c == '#').count();
    if hash_count > 0 && hash_count <= 6 {
        if let Some(rest) = trimmed.get(hash_count..) {
            let text = rest.trim();
            if !text.is_empty() {
                let content = parse_inline(text);
                return format!("<h{}>{}</h{}>", hash_count, content, hash_count);
            }
        }
    }
    format!("<p>{}</p>", parse_inline(trimmed))
}

fn parse_inline(text: &str) -> String {
    let mut result = String::new();
    let chars: Vec<char> = text.chars().collect();
    let mut i = 0;
    while i < chars.len() {
        if i + 1 < chars.len() && chars[i] == '*' && chars[i + 1] == '*' {
            // Find closing **
            if let Some(end) = text[i + 2..].find("**") {
                result.push_str("<strong>");
                result.push_str(&text[i + 2..i + 2 + end]);
                result.push_str("</strong>");
                i += end + 4;
                continue;
            }
        }
        result.push(chars[i]);
        i += 1;
    }
    result
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_paragraph() {
        assert!(to_html("hello").contains("<p>hello</p>"));
    }

    #[test]
    fn test_heading_h1() {
        assert!(to_html("# Title").contains("<h1>Title</h1>"));
    }

    #[test]
    fn test_heading_h3() {
        assert!(to_html("### Sub").contains("<h3>Sub</h3>"));
    }

    #[test]
    fn test_bold() {
        assert!(to_html("**bold**").contains("<strong>bold</strong>"));
    }

    #[test]
    fn test_bold_in_heading() {
        let html = to_html("# Hello **world**");
        assert!(html.contains("<h1>"));
        assert!(html.contains("<strong>world</strong>"));
    }
}
